# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
import shutil
import hashlib
import mimetypes
from datetime import datetime
from pathlib import Path
from typing import Optional

from fastapi import FastAPI, HTTPException, Query, UploadFile, File, Depends
from fastapi.responses import FileResponse, JSONResponse
from pydantic import BaseModel


app = FastAPI(title="File Explorer API")

# Base directory where all user files are stored
BASE_UPLOAD_DIR = os.path.abspath(os.path.join(os.path.dirname(__file__), "user_files"))

# Ensure the base directory exists
os.makedirs(BASE_UPLOAD_DIR, exist_ok=True)


class FileInfo(BaseModel):
    name: str
    path: str
    size: int
    is_directory: bool
    created: str
    modified: str
    mime_type: Optional[str] = None
    md5: Optional[str] = None


class DirectoryListing(BaseModel):
    path: str
    entries: list[FileInfo]
    total_entries: int


class MessageResponse(BaseModel):
    message: str
    path: str


def get_user_root(user_id: str = Query(default="default_user", description="User ID")) -> str:
    """Get the root directory for a given user and ensure it exists."""
    user_root = os.path.abspath(os.path.join(BASE_UPLOAD_DIR, user_id))
    os.makedirs(user_root, exist_ok=True)
    return user_root


def resolve_safe_path(user_root: str, relative_path: str) -> str:
    """
    Resolve a user-provided relative path to a safe absolute path.
    Uses os.path.join to construct the full path and os.path.normpath
    to normalize it (handling '..' etc.). Then verifies the result
    is still within the user's root directory to prevent path traversal.
    """
    # Join the user root with the relative path
    joined = os.path.join(user_root, relative_path)

    # Normalize the path to resolve '..' and other components
    normalized = os.path.normpath(joined)

    # Convert to absolute path
    absolute = os.path.abspath(normalized)

    # Security check: ensure the resolved path is within the user's root
    user_root_abs = os.path.abspath(user_root)
    if not absolute.startswith(user_root_abs + os.sep) and absolute != user_root_abs:
        raise HTTPException(
            status_code=403,
            detail="Access denied: path traversal detected. The resolved path is outside your root directory."
        )

    return absolute


def get_file_md5(filepath: str) -> str:
    """Calculate MD5 hash of a file."""
    hash_md5 = hashlib.md5()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            hash_md5.update(chunk)
    return hash_md5.hexdigest()


def build_file_info(full_path: str, user_root: str) -> FileInfo:
    """Build a FileInfo object for a given file/directory path."""
    stat = os.stat(full_path)
    is_dir = os.path.isdir(full_path)
    name = os.path.basename(full_path)

    # Get the relative path from user root
    rel_path = os.path.relpath(full_path, user_root)
    if rel_path == ".":
        rel_path = "/"

    mime_type = None
    md5 = None
    if not is_dir:
        mime_type, _ = mimetypes.guess_type(full_path)
        if mime_type is None:
            mime_type = "application/octet-stream"
        # Only compute md5 for files under a reasonable size (e.g., 100MB)
        if stat.st_size < 100 * 1024 * 1024:
            md5 = get_file_md5(full_path)

    return FileInfo(
        name=name,
        path=rel_path,
        size=stat.st_size,
        is_directory=is_dir,
        created=datetime.fromtimestamp(stat.st_ctime).isoformat(),
        modified=datetime.fromtimestamp(stat.st_mtime).isoformat(),
        mime_type=mime_type,
        md5=md5,
    )


@app.get("/api/files/list", response_model=DirectoryListing)
def list_directory(
    path: str = Query(default="", description="Relative path to directory within user root"),
    user_root: str = Depends(get_user_root),
):
    """
    List the contents of a directory.
    Users provide a path relative to their root directory.
    """
    full_path = resolve_safe_path(user_root, path)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail=f"Directory not found: {path}")

    if not os.path.isdir(full_path):
        raise HTTPException(status_code=400, detail=f"Path is not a directory: {path}")

    entries = []
    try:
        for entry_name in sorted(os.listdir(full_path)):
            entry_full_path = os.path.join(full_path, entry_name)
            try:
                file_info = build_file_info(entry_full_path, user_root)
                entries.append(file_info)
            except (PermissionError, OSError):
                # Skip entries we can't access
                continue
    except PermissionError:
        raise HTTPException(status_code=403, detail=f"Permission denied for directory: {path}")

    rel_path = os.path.relpath(full_path, user_root)
    if rel_path == ".":
        rel_path = "/"

    return DirectoryListing(
        path=rel_path,
        entries=entries,
        total_entries=len(entries),
    )


@app.get("/api/files/info", response_model=FileInfo)
def get_file_info(
    path: str = Query(description="Relative path to file or directory within user root"),
    user_root: str = Depends(get_user_root),
):
    """
    Get detailed information about a specific file or directory.
    """
    full_path = resolve_safe_path(user_root, path)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail=f"File or directory not found: {path}")

    try:
        return build_file_info(full_path, user_root)
    except PermissionError:
        raise HTTPException(status_code=403, detail=f"Permission denied: {path}")


@app.get("/api/files/download")
def download_file(
    path: str = Query(description="Relative path to file within user root"),
    user_root: str = Depends(get_user_root),
):
    """
    Download a file. Users provide the path relative to their root directory.
    """
    full_path = resolve_safe_path(user_root, path)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail=f"File not found: {path}")

    if os.path.isdir(full_path):
        raise HTTPException(status_code=400, detail=f"Cannot download a directory: {path}. Use list endpoint instead.")

    filename = os.path.basename(full_path)
    mime_type, _ = mimetypes.guess_type(full_path)
    if mime_type is None:
        mime_type = "application/octet-stream"

    return FileResponse(
        path=full_path,
        filename=filename,
        media_type=mime_type,
    )


@app.post("/api/files/upload", response_model=FileInfo)
async def upload_file(
    path: str = Query(default="", description="Relative directory path to upload into"),
    file: UploadFile = File(description="File to upload"),
    user_root: str = Depends(get_user_root),
):
    """
    Upload a file to the specified directory path.
    """
    target_dir = resolve_safe_path(user_root, path)

    if not os.path.exists(target_dir):
        os.makedirs(target_dir, exist_ok=True)

    if not os.path.isdir(target_dir):
        raise HTTPException(status_code=400, detail=f"Target path is not a directory: {path}")

    filename = file.filename or "uploaded_file"
    # Sanitize filename
    filename = os.path.basename(filename)
    if not filename:
        filename = "uploaded_file"

    destination = os.path.join(target_dir, filename)
    destination = os.path.normpath(destination)

    # Verify the destination is still within user root
    user_root_abs = os.path.abspath(user_root)
    if not os.path.abspath(destination).startswith(user_root_abs + os.sep):
        raise HTTPException(status_code=403, detail="Invalid filename")

    try:
        with open(destination, "wb") as f:
            while True:
                chunk = await file.read(8192)
                if not chunk:
                    break
                f.write(chunk)
    except IOError as e:
        raise HTTPException(status_code=500, detail=f"Failed to save file: {str(e)}")

    return build_file_info(destination, user_root)


@app.delete("/api/files/delete", response_model=MessageResponse)
def delete_file(
    path: str = Query(description="Relative path to file or directory to delete"),
    user_root: str = Depends(get_user_root),
):
    """
    Delete a file or directory.
    """
    if not path or path == "/" or path == ".":
        raise HTTPException(status_code=400, detail="Cannot delete the root directory")

    full_path = resolve_safe_path(user_root, path)

    if not os.path.exists(full_path):
        raise HTTPException(status_code=404, detail=f"File or directory not found: {path}")

    try:
        if os.path.isdir(full_path):
            shutil.rmtree(full_path)
        else:
            os.remove(full_path)
    except PermissionError:
        raise HTTPException(status_code=403, detail=f"Permission denied: {path}")
    except OSError as e:
        raise HTTPException(status_code=500, detail=f"Failed to delete: {str(e)}")

    return MessageResponse(message="Successfully deleted", path=path)


@app.post("/api/files/mkdir", response_model=FileInfo)
def create_directory(
    path: str = Query(description="Relative path for the new directory"),
    user_root: str = Depends(get_user_root),
):
    """
    Create a new directory at the specified path.
    """
    full_path = resolve_safe_path(user_root, path)

    if os.path.exists(full_path):
        raise HTTPException(status_code=409, detail=f"Path already exists: {path}")

    try:
        os.makedirs(full_path, exist_ok=False)
    except OSError as e:
        raise HTTPException(status_code=500, detail=f"Failed to create directory: {str(e)}")

    return build_file_info(full_path, user_root)


@app.get("/api/files/search")
def search_files(
    query: str = Query(description="Search query (filename pattern)"),
    path: str = Query(default="", description="Relative directory path to search within"),
    user_root: str = Depends(get_user_root),
):
    """
    Search for files matching a query within the specified directory (recursively).
    """
    search_root = resolve_safe_path(user_root, path)

    if not os.path.exists(search_root):
        raise HTTPException(status_code=404, detail=f"Directory not found: {path}")

    if not os.path.isdir(search_root):
        raise HTTPException(status_code=400, detail=f"Path is not a directory: {path}")

    results = []
    query_lower = query.lower()

    for dirpath, dirnames, filenames in os.walk(search_root):
        for name in filenames + dirnames:
            if query_lower in name.lower():
                full = os.path.join(dirpath, name)
                try:
                    results.append(build_file_info(full, user_root))
                except (PermissionError, OSError):
                    continue

        # Limit results
        if len(results) >= 100:
            break

    return {
        "query": query,
        "search_path": path or "/",
        "results": results,
        "total_results": len(results),
    }


